-- Add insurerRole field to users table
ALTER TABLE users ADD COLUMN insurerRole TEXT CHECK(insurerRole IN ('claims_processor', 'internal_assessor', 'risk_manager', 'claims_manager', 'executive')) DEFAULT NULL;

-- Update existing insurer users to claims_manager role (highest operational access)
UPDATE users SET insurerRole = 'claims_manager' WHERE role = 'insurer';

